-- V17__Merged_Master_Tests.sql
-- ================================================================
-- MERGED from V11 (498 tests) + V14 (88 tests) + 1000_seed (794 tests)
-- Total unique tests after deduplication: 1058
-- Prices capped/fixed to realistic Indian lab market rates
-- All categories normalized. No duplicates. No junk data.
-- Replaces V11, V14 insert logic. V15 DELETE+88 also replaced.

SET @tests_sql = (
    SELECT IF(
        NOT EXISTS (
            SELECT 1
            FROM information_schema.columns
            WHERE table_schema = DATABASE()
              AND table_name = 'tests'
              AND column_name = 'is_top_booked'
        ),
        'ALTER TABLE tests ADD COLUMN is_top_booked BOOLEAN DEFAULT FALSE',
        'SELECT 1'
    )
);
PREPARE tests_stmt FROM @tests_sql;
EXECUTE tests_stmt;
DEALLOCATE PREPARE tests_stmt;

SET @tests_sql = (
    SELECT IF(
        NOT EXISTS (
            SELECT 1
            FROM information_schema.columns
            WHERE table_schema = DATABASE()
              AND table_name = 'tests'
              AND column_name = 'is_top_deal'
        ),
        'ALTER TABLE tests ADD COLUMN is_top_deal BOOLEAN DEFAULT FALSE',
        'SELECT 1'
    )
);
PREPARE tests_stmt FROM @tests_sql;
EXECUTE tests_stmt;
DEALLOCATE PREPARE tests_stmt;

SET @tests_sql = (
    SELECT IF(
        NOT EXISTS (
            SELECT 1
            FROM information_schema.columns
            WHERE table_schema = DATABASE()
              AND table_name = 'tests'
              AND column_name = 'parameters_count'
        ),
        'ALTER TABLE tests ADD COLUMN parameters_count INT DEFAULT 0',
        'SELECT 1'
    )
);
PREPARE tests_stmt FROM @tests_sql;
EXECUTE tests_stmt;
DEALLOCATE PREPARE tests_stmt;

DELETE FROM tests;

